/* ============================================
   LOOPING VIDEO — plugin-spesifikk styling
   Bygger på src/style.css (designsystem)
   ============================================ */

.plugin-page {
  flex: 1;
  display: grid;
  grid-template-columns: 313px 1fr;
  gap: 22px;
  overflow: hidden;
  padding: 4px;
}

/* ============================================
   Venstre sidebar
   ============================================ */
.plugin-sidebar {
  display: flex;
  flex-direction: column;
  gap: 16px;
  padding: 0 4px;
}

.plugin-sidebar__title {
  font-family: var(--font-bold);
  font-size: 27px;
  font-weight: bold;
  color: #212121;
  margin: 0;
  line-height: 1.05;
}

.plugin-sidebar__desc {
  font-family: var(--font-regular);
  font-size: 15px;
  color: #fff;
  margin: 0;
  line-height: 1.4;
}

.plugin-sidebar__desc em {
  font-style: normal;
  font-family: var(--font-bold);
  font-weight: bold;
}

.plugin-sidebar__spacer { flex: 1; }

/* Caption + photographer-felter */
.caption-section {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.caption-input {
  background: var(--bg-input);
  border: 0;
  outline: 0;
  border-radius: var(--radius-input);
  padding: 10px 14px;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: 13px;
  color: var(--text-input);
  resize: vertical;
  line-height: 1.35;
  font-family: inherit;
}
.caption-input--single { height: 36px; padding: 8px 14px; }
.caption-input::placeholder {
  color: #888;
  font-weight: normal;
}

.caption-hint {
  font-family: var(--font-regular);
  font-size: 12px;
  color: #fff;
  opacity: 0.75;
  margin: 6px 0 0;
  line-height: 1.4;
}
.caption-hint strong { font-weight: bold; }

.plugin-sidebar__status {
  font-size: 13px;
  color: #fff;
  min-height: 18px;
  font-family: var(--font-regular);
  opacity: 0.85;
}

/* URL-seksjon: label + input-rad i normal flow (ingen absolute) */
.url-section {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.url-section__label {
  font-family: var(--font-bold);
  font-size: 13px;
  font-weight: bold;
  color: #fff;
  letter-spacing: 0.02em;
}

.url-section__header {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 8px;
}

/* Liten tekst-lenke-knapp — åpner ekstern side i nettleser */
.link-btn {
  background: transparent;
  color: #fff;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: 12px;
  padding: 2px 0;
  cursor: pointer;
  text-decoration: underline;
  text-decoration-color: rgba(255,255,255,0.5);
  text-underline-offset: 3px;
  transition: text-decoration-color 0.15s, color 0.15s;
}
.link-btn:hover {
  text-decoration-color: #fff;
  color: #fff;
}

.url-row {
  background: var(--bg-input);
  height: 41px;
  border-radius: var(--radius-input);
  padding: 0 4px 0 17px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.url-row__input {
  flex: 1;
  background: transparent;
  border: 0;
  outline: 0;
  height: 100%;
  font-family: var(--font-bold);
  font-size: 13px;
  color: var(--text-input);
  font-weight: bold;
  min-width: 0;
}
.url-row__input::placeholder {
  color: #888;
  font-weight: normal;
}

.btn-tiny {
  background: var(--faktisk-blue);
  color: #fff;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: 13px;
  height: 30px;
  padding: 0 12px;
  border-radius: var(--radius-input);
  white-space: nowrap;
  transition: background 0.15s;
}
.btn-tiny:hover { background: var(--faktisk-blue-hover); }

/* Eksport-knapper i sidebar — side om side for å spare plass */
.export-row {
  display: flex;
  gap: 8px;
}
.export-row__btn {
  flex: 1;
  min-width: 0;
  padding: 0 8px;
  font-size: 14px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

/* Prosjekt-rad — dropdown + lagre-knapp stablet vertikalt så de får plass
   i den smale 313px-sidebaren */
.project-row {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.project-select {
  width: 100%;
  height: 36px;
  background: var(--bg-input);
  border: 0;
  border-radius: var(--radius-input);
  padding: 0 32px 0 12px;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: 13px;
  color: var(--text-input);
  cursor: pointer;
  appearance: none;
  -webkit-appearance: none;
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='12' height='8' viewBox='0 0 12 8'><path d='M1 1l5 5 5-5' stroke='%23313131' stroke-width='2' fill='none' stroke-linecap='round' stroke-linejoin='round'/></svg>");
  background-repeat: no-repeat;
  background-position: right 12px center;
}
.project-select:focus { outline: 2px solid var(--faktisk-blue); }

/* Lagre-knapp tar full bredde av spalten */
.project-row .btn-tiny {
  width: 100%;
  height: 36px;
}

.btn-secondary {
  background: rgba(255,255,255,0.16);
  color: #fff;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: 15px;
  height: 52px;
  padding: 0 22px;
  border-radius: var(--radius-button);
  transition: background 0.15s;
}
.btn-secondary:hover { background: rgba(255,255,255,0.24); }
.btn-secondary:disabled,
.btn-primary:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

/* ============================================
   Høyre canvas
   ============================================ */
.plugin-canvas {
  display: flex;
  flex-direction: column;
  gap: 12px;
  overflow: hidden;
  min-width: 0;
}

.canvas-area {
  position: relative;
  flex: 1;
  background: var(--bg-letterbox);
  border-radius: 10px;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
}

.canvas-video {
  display: block;
  max-width: 100%;
  max-height: 100%;
  width: auto;
  height: auto;
  border-radius: 6px;
  background: #000;
}
.canvas-video:not([src]) { display: none; }

.canvas-empty {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 40px;
  text-align: center;
}
.canvas-empty p {
  max-width: 420px;
  font-family: var(--font-regular);
  font-size: 16px;
  color: #fff;
  margin: 0;
  line-height: 1.4;
}
.canvas-empty.hidden { display: none; }

/* ============================================
   Tidslinje (dual-handle trim-slider)
   ============================================ */
.timeline {
  flex-shrink: 0;
  padding: 8px 30px 0;
}

.timeline__track {
  position: relative;
  height: 18px;
  background: #6F6F6F;        /* hele tidslinjen — mørkere grå */
  border-radius: 4px;
  cursor: pointer;
}

/* Det valgte klippet — tydelig Faktisk-blå så det er åpenbart hva som havner i embed */
.timeline__selection {
  position: absolute;
  top: 0;
  bottom: 0;
  background: var(--faktisk-blue);
  pointer-events: none;
  z-index: 1;
}

.timeline__handle {
  position: absolute;
  top: -7px;
  bottom: -7px;
  width: 14px;
  background: var(--faktisk-blue);
  border: 2px solid #fff;
  border-radius: 4px;
  cursor: ew-resize;
  transform: translateX(-50%);
  z-index: 3;
  transition: background 0.15s, transform 0.1s;
  box-shadow: 0 2px 6px rgba(0,0,0,0.35);
}
.timeline__handle:hover { background: var(--faktisk-blue-hover); }
.timeline__handle:active { transform: translateX(-50%) scale(1.05); }
.timeline__handle--start { left: 0; }
.timeline__handle--end { left: 100%; }

/* Liten "grip"-indikator inni håndtaket */
.timeline__handle::after {
  content: '';
  position: absolute;
  left: 50%;
  top: 50%;
  width: 2px;
  height: 16px;
  background: rgba(255,255,255,0.85);
  transform: translate(-50%, -50%);
  border-radius: 1px;
}

.timeline__labels {
  display: flex;
  justify-content: space-between;
  margin-top: 8px;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: 12px;
  color: #fff;
  opacity: 0.85;
}
.timeline__labels span:nth-child(2) {
  flex: 1;
  text-align: center;
}
